CREATE TRIGGER LG_EMUHACC_UPD_223 ON LG_223_EMUHACC
FOR UPDATE
AS
DECLARE @sBuffer        VARCHAR(110),
        @upperRef       INT,
        @old_Code       VARCHAR(110),
        @old_accountRef INT,
        @new_Code       VARCHAR(110),
        @new_accountRef INT,
        @new_level      INT
SELECT @old_accountRef = D.LOGICALREF,
       @old_Code= D.CODE
FROM DELETED D
SELECT @new_accountRef = I.LOGICALREF,
       @new_Code = I.CODE,
       @new_level = I.LEVEL_
FROM INSERTED I
IF @old_Code <> @new_Code
BEGIN
      SET @upperRef = @new_accountRef
      WHILE (@upperRef <> 0)
       BEGIN
          IF NOT EXISTS(SELECT * FROM LG_223_EMUHACCSUBACCASGN
                        WHERE ACCOUNTREF = @upperRef AND SUBACCOUNTREF = @new_accountRef)
           INSERT INTO LG_223_EMUHACCSUBACCASGN VALUES(@upperRef,@new_accountRef)
          EXEC LG_GETEMUHACCUPPERCODE_223 @new_Code, @new_level, @sBuffer OUTPUT, @upperRef OUTPUT
          SET @new_level = @new_level -1
       END
END
